const greetings = [
  "Xin chào quý khách! Em là Jerry – trợ lý tư vấn của Anrealshop. Em rất vui được hỗ trợ anh/chị tìm kiếm sản phẩm thời trang phù hợp, từ trang phục hàng ngày đến các bộ sưu tập cao cấp. Anh/chị đang quan tâm đến mẫu nào hôm nay ạ?",
  "Chào mừng anh/chị đến với Anrealshop! Em là Jerry, sẵn sàng đồng hành cùng anh/chị trong việc lựa chọn phong cách thời trang. Anh/chị cần em gợi ý sản phẩm, tư vấn phối đồ hay thông tin về chương trình khuyến mãi ạ?",
  "Xin chào anh/chị! Jerry đây ạ – trợ lý ảo của Anrealshop. Em luôn sẵn sàng hỗ trợ anh/chị khám phá các bộ sưu tập mới nhất, sản phẩm bán chạy hoặc các thiết kế độc quyền. Anh/chị muốn bắt đầu từ đâu ạ?",
  "Chào anh/chị! Rất hân hạnh được chào đón anh/chị tại Anrealshop. Em là Jerry, chuyên tư vấn về thời trang và phong cách cá nhân. Hôm nay anh/chị đang tìm kiếm trang phục cho dịp nào đặc biệt ạ?",
  "Xin chào! Em là Jerry từ Anrealshop. Với đa dạng sản phẩm từ basic đến cao cấp, em tin chắc sẽ tìm được những món đồ hoàn hảo cho anh/chị. Anh/chị đang cần hỗ trợ về danh mục nào ạ?",
  "Chào mừng anh/chị ghé thăm Anrealshop! Em là Jerry – trợ lý tư vấn thời trang. Em rất mong được hỗ trợ anh/chị chọn lựa sản phẩm phù hợp với sở thích và nhu cầu. Anh/chị có ý tưởng phong cách nào đang ấp ủ không ạ?",
  "Xin chào quý khách! Jerry – trợ lý của Anrealshop xin gửi lời chào trân trọng. Em luôn sẵn sàng cung cấp thông tin chi tiết về sản phẩm, kích cỡ, chất liệu hay các chương trình ưu đãi hiện hành. Anh/chị cần em hỗ trợ gì trước tiên ạ?",
  "Chào anh/chị! Em là Jerry từ Anrealshop. Chúng em tự hào mang đến những thiết kế thời thượng, chất lượng cao. Anh/chị đang tìm kiếm trang phục cho công việc, dạo phố hay sự kiện đặc biệt ạ?",
  "Xin chào! Rất vui được gặp anh/chị tại Anrealshop. Em là Jerry, sẵn sàng tư vấn và giới thiệu các sản phẩm mới nhất cũng như những mẫu đang được ưa chuộng. Anh/chị cho em biết mong muốn của mình nhé ạ?",
  "Chào mừng anh/chị đến với Anrealshop! Em là Jerry – trợ lý tư vấn chuyên nghiệp. Từ trang phục nam, nữ đến phụ kiện, em sẽ hỗ trợ anh/chị một cách tận tình nhất. Hôm nay anh/chị muốn khám phá điều gì ạ?",
  "Xin chào quý khách! Em là Jerry của Anrealshop. Với sứ mệnh mang đến phong cách tinh tế và thoải mái, em rất mong được đồng hành cùng anh/chị. Anh/chị đang cần gợi ý sản phẩm hay thông tin gì đặc biệt ạ?",
  "Chào anh/chị! Jerry từ Anrealshop xin chào. Em luôn cập nhật xu hướng thời trang mới nhất và sẵn sàng tư vấn chi tiết. Anh/chị đang tìm kiếm bộ sưu tập nào hoặc cần hỗ trợ phối đồ ạ?"
];

const randomGreeting = greetings[Math.floor(Math.random() * greetings.length)];

return {
  json: {
    message: randomGreeting,
    type: "Greeting"
  }
};

const funnyRejections = [
  "Ối zời ơi, anh/chị hỏi em cái này em chịu thua luôn á! Em là chuyên gia thời trang chứ không phải chuyên gia thời tiết/sức khỏe/tài chính đâu nè. Nhưng mà... shop đang có mấy em áo hoodie siêu ấm, siêu xinh, mặc đi Nha Trang chiều chiều mát mẻ lắm đấy ạ! Anh/chị muốn xem không ạ? 😄",
  "Hihi, câu hỏi này ngoài phạm vi 'thời trang' của em rồi nha! Jerry chỉ giỏi 'chốt đơn' quần áo, giày dép thôi. Mà tiện đây, em thấy có mấy mẫu sneaker mới về đẹp mê ly, anh/chị đang cần đôi nào để đi dạo biển Nha Trang không ạ? 👟",
  "Em xin lỗi nha anh/chị, em không rành vụ này lắm đâu ạ... Nhưng em rành vụ làm đẹp tủ đồ lắm! Hôm nay shop có deal hot cho áo thun basic và quần short hè, mặc mát mẻ ở Nha Trang cực kỳ. Anh/chị muốn em gợi ý size nào không ạ? 🛍️",
  "Trời ơi, anh/chị hỏi em cái này em 'đơ' luôn á! Em chỉ biết tư vấn style, phối đồ, săn sale thôi. Mà nói thật, mặc đồ đẹp là cách tốt nhất để 'chill' mọi ngày rồi đấy ạ. Anh/chị đang cần outfit nào để lên đồ hôm nay không nè?",
  "Haha, em chịu thua câu hỏi này rồi! Jerry là trợ lý thời trang, không phải trợ lý Google đâu ạ. Nhưng em có thể giúp anh/chị 'level up' phong cách ngay bây giờ. Shop đang có bộ sưu tập hè mới, nhẹ nhàng, thoáng mát, hợp với khí hậu Nha Trang lắm. Xem thử nhé ạ?",
  "Anh/chị ơi, em chỉ 'pro' về thời trang thôi, mấy chuyện khác em 'ngáo ngơ' lắm á! Nhưng đừng lo, em biết cách làm anh/chị đẹp hơn mỗi ngày. Có mẫu váy maxi bay bổng hay áo sơ mi linen đang hot lắm, mặc đi biển Nha Trang là hết sảy. Anh/chị thích kiểu nào ạ?",
  "Xin lỗi anh/chị nha, chủ đề này em 'out of stock' kiến thức rồi ạ! Nhưng chủ đề thời trang thì em có hàng full luôn. Hôm nay shop có khuyến mãi giảm 20% cho phụ kiện, túi xách, kính mát – hợp đi dạo Nha Trang quá trời. Anh/chị cần em gửi link không ạ?",
  "Câu hỏi khó quá trời luôn á anh/chị! Em chỉ giỏi 'match' đồ với người thôi. Mà tiện thể, em thấy anh/chị ở Nha Trang chắc thích đồ thoải mái, mát mẻ đúng không ạ? Shop có mấy set đồ linen, cotton organic xịn sò lắm, xem không nè?",
  "Em 'bó tay' với câu hỏi này rồi ạ! Nhưng em không bó tay với việc giúp anh/chị đẹp hơn đâu nha. Anrealshop đang có hàng mới về liên tục: áo polo, quần kaki, giày thể thao... Anh/chị muốn em recommend theo style nào ạ?",
  "Hihi, anh/chị thử thách em rồi nè! Em chỉ biết tư vấn 'đẹp – rẻ – chất' thôi. Mà nói thật, mặc đồ đẹp là cách vui nhất để quên hết mọi thứ khác đó ạ. Anh/chị đang cần set đồ đi làm, đi chơi hay đi biển ở Nha Trang ạ?"
];

const randomRejection = funnyRejections[Math.floor(Math.random() * funnyRejections.length)];

const message = `${randomRejection}\n\nBạn có muốn em giúp tìm sản phẩm, xem deal hot, hay gợi ý outfit nào phù hợp với thời tiết Nha Trang hôm nay không ạ?`;

return {
  json: {
    message: message,
    type: "NotFashion"
  }
};

const results = $input.all();
const classifierOutput = $('AI Agent Classifier').first().json.output || {};
const queryType = classifierOutput.query_type || 'unknown';
const userIntent = classifierOutput.intent || '';

// Trường hợp không có kết quả từ SQL
if (!results || results.length === 0) {
  return {
    json: {
      data: JSON.stringify({
        error: true,
        queryType: queryType,
        intent: userIntent,
        items: []
      })
    }
  };
}

// Xử lý từng item từ kết quả SQL
const processedItems = results.map(item => {
  const data = item.json;

  // Ưu tiên dùng các giá trị đã tính sẵn từ SQL (nếu có)
  const currentPrice = data.gia_hien_tai ||
                      (data.gia_giam && data.gia_giam > 0 ? data.gia_giam : data.gia_goc);

  const discountPercent = data.phan_tram_giam ||
                         (data.gia_giam > 0 && data.gia_goc > 0
                           ? Math.round((1 - data.gia_giam / data.gia_goc) * 100)
                           : 0);

  return {
    id: data.id_san_pham || data.id_cua_hang || data.id_danh_muc || null,
    name: data.ten_san_pham || data.ten_cua_hang || data.ten_danh_muc || "Chưa có tên",
    price: currentPrice,
    original_price: data.gia_goc || null,
    discount: discountPercent,
    rating: data.diem_danh_giatb ? parseFloat(data.diem_danh_giatb).toFixed(1) : 0,
    total_reviews: data.tong_danh_gia || 0,
    sold: data.da_ban || 0,
    thumbnail: data.thumbnail || data.anh_dai_dien || null,
    product_url: data.product_url || null,
    short_description: data.short_description || data.mo_ta_ngan || data.mo_ta || null,
    shop_name: data.shop_name || data.ten_cua_hang || "Chưa có thông tin shop",
    shop_id: data.id_cua_hang || null,
    category_name: data.category_name || data.ten_danh_muc || "Chưa phân loại"
  };
});

// LỌC BỎ ITEM RÁC (đây là phần sửa chính)
const validItems = processedItems.filter(item => {
  const hasValidName = item.name && 
                       item.name.trim() !== '' && 
                       item.name !== "Chưa có tên" && 
                       item.name !== "Chưa có";

  const hasValidPrice = item.price != null && item.price > 0;

  // Có thể thêm điều kiện khác nếu cần, ví dụ: thumbnail != null
  return hasValidName && hasValidPrice;
});

// Quyết định error và items
const hasValidData = validItems.length > 0;

return {
  json: {
    data: JSON.stringify({
      error: !hasValidData,
      queryType: queryType,
      intent: userIntent,
      items: hasValidData ? validItems : []   // <-- Đảm bảo rỗng nếu không hợp lệ
    })
  }
};

// 1. Lấy dữ liệu từ node Format data với cơ chế an toàn
let inputData = { error: false, items: [], queryType: 'unknown' };
try {
  // Lấy dữ liệu từ node 'Format data', nếu không có thì mặc định mảng rỗng
  const rawData = $('Format data').first()?.json?.data;
  if (rawData) {
    inputData = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
  }
} catch (e) {
  console.error("Lỗi parse inputData:", e);
  inputData.error = true;
}

// 2. Lấy output từ AI Agent Format
const aiOutput = $input.first()?.json || {};
let aiMessage = aiOutput.output || aiOutput.message || aiOutput.text || "";

// 3. Khởi tạo các biến chứa kết quả
let finalMessage = "";
let imageUrls = [];
let productLink = null;

// Kiểm tra xem thực tế có sản phẩm nào không
const hasProducts = inputData.items && inputData.items.length > 0;

// 4. Logic xử lý Message
// Điều kiện ưu tiên AI: AI có trả về message hợp lệ VÀ DB thực sự có sản phẩm
const isAiMessageValid = aiMessage && aiMessage.trim().length > 10 && aiMessage.includes('Anrealshop');

if (hasProducts && isAiMessageValid) {
  // --- TRƯỜNG HỢP 1: CÓ SẢN PHẨM VÀ AI PHẢN HỒI TỐT ---
  finalMessage = aiMessage.trim();
  finalMessage = finalMessage.replace(/\n{3,}/g, '\n\n').replace(/\s{2,}/g, ' ');

  // Trích xuất ảnh từ tag [IMAGE:...]
  const imageTagRegex = /\[IMAGE:(https?:\/\/[^\]\s]+)\]/gi;
  let match;
  while ((match = imageTagRegex.exec(finalMessage)) !== null) {
    imageUrls.push(match[1]);
  }
  finalMessage = finalMessage.replace(imageTagRegex, '').trim();

  // Trích xuất link sản phẩm từ nội dung AI
  const xemChiTietRegex = /-\s*Xem chi tiết:\s*([^\n]+)/i;
  const matchXemChiTiet = finalMessage.match(xemChiTietRegex);
  if (matchXemChiTiet && matchXemChiTiet[1]) {
    productLink = matchXemChiTiet[1].trim()
      .replace(/^https?:\/\/anrealshop\.com\/san-pham\//i, '')
      .replace(/\s+$/, '');
    if (productLink && !productLink.startsWith('/')) productLink = '/' + productLink;
  }

  // Xóa dòng link thô trong message để giao diện sạch hơn (nếu cần giữ thì comment dòng này)
  finalMessage = finalMessage.replace(/-\s*Xem chi tiết:[^\n]*/gi, '').trim();

} else if (hasProducts) {
  // --- TRƯỜNG HỢP 2: CÓ SẢN PHẨM NHƯNG AI LỖI/KHÔNG TRẢ VỀ (FALLBACK) ---
  const itemCount = inputData.items.length;
  finalMessage = `Dạ, em tìm thấy ${itemCount} sản phẩm phù hợp tại Anrealshop ạ:\n\n`;

  inputData.items.slice(0, 3).forEach((item, idx) => {
    const formattedPrice = new Intl.NumberFormat('vi-VN').format(item.price || item.gia_hien_tai || 0) + 'đ';
    finalMessage += `${idx + 1}. ${item.name || item.ten_san_pham || 'Sản phẩm'}\n`;
    finalMessage += `- Giá: ${formattedPrice}\n`;
    finalMessage += `- Shop: ${item.shop_name || 'Anrealshop'}\n\n`;

    if (!productLink && item.product_url) {
      productLink = item.product_url.startsWith('/') ? item.product_url : '/' + item.product_url;
    }
    if (item.thumbnail || item.anh_dai_dien) {
      imageUrls.push(item.thumbnail || item.anh_dai_dien);
    }
  });

  finalMessage += "Anh/chị nhấn vào sản phẩm để xem chi tiết nhé!";

} else {
  // --- TRƯỜNG HỢP 3: KHÔNG TÌM THẤY SẢN PHẨM ---
  finalMessage = "Dạ, hiện tại em chưa tìm thấy sản phẩm nào đúng ý anh/chị rồi ạ. Anh/chị thử tìm với từ khóa khác hoặc mô tả chi tiết hơn (ví dụ: 'áo thun đen cotton') để em hỗ trợ nhé!";
}

// 5. Củng cố dữ liệu bổ trợ (Ảnh/Link)
if (imageUrls.length === 0 && hasProducts) {
  const firstThumb = inputData.items[0].thumbnail || inputData.items[0].anh_dai_dien;
  if (firstThumb) imageUrls.push(firstThumb);
}

if (!productLink && hasProducts) {
  productLink = inputData.items[0].product_url || null;
}

// 6. Trả về kết quả cuối cùng
return {
  json: {
    message: finalMessage.trim(),
    type: !hasProducts ? "No_Data" : "Success",
    queryType: inputData.queryType || 'product_search',
    imageUrl: imageUrls[0] || null,
    imageUrls: imageUrls.slice(0, 5),
    productLink: productLink
  }
};
